// ============================================================
// FILTER ENGINE — Dual Webhook Version
// Webhook 316  → users, departments, notifications
// Webhook 71603 → activities, deals
// Window: past 30 days (overdue) + today + next 30 days (upcoming)
// ============================================================

const MAIN_WEBHOOK     = 'https://intranet.rajlaxmiworld.com/rest/1/65xnwve29k4aybeh';
const ACTIVITY_WEBHOOK = 'https://intranet.rajlaxmiworld.com/rest/71603/jqz6l15bjdnyx803';
const BITRIX_DOMAIN    = 'https://intranet.rajlaxmiworld.com';
const BREVO_API_KEY    = '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';
const FROM_EMAIL       = 'info@averlonworld.com';
const FROM_NAME        = 'Averlon CRM';
const HOD_USER_ID      = '316';
const HOD_NAME         = 'Bhagwati Dhandharia';
const HOD_EMAIL        = 'bhagwati@rajlaxmiworld.com';
const TARGET_DEPARTMENT = 'Bitrix24 Team';
const MAX_DEALS_PER_MSG = 8;

// [] = ALL employees in department
// [{id:'34574', name:'Mansi Jaiswal', email:'mansi@rajlaxmiworld.com'}] = specific only
const SELECTED_EMPLOYEES = [];

// ── IST time setup ────────────────────────────────────────
const nowIST = new Date(
  new Date().toLocaleString("en-US", { timeZone: "Asia/Kolkata" })
);
const todayStr = nowIST.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
//const todayStr  = nowIST.toISOString().slice(0, 10);
const istHour   = nowIST.getHours();
const istMinute = nowIST.getMinutes();

// ── Trigger slot detection ────────────────────────────────
//const isReminder1  = (istHour === 10 && istMinute < 0);
//const isReminder2  = (istHour === 14 && istMinute < 0);
//const isReminder3  = (istHour === 17 && istMinute < 0);

const isReminder1  = (istHour === 10 && istMinute >= 0 && istMinute < 40);
const isReminder2  = (istHour === 13 && istMinute >= 0 && istMinute < 55);
const isReminder3  = (istHour === 17 && istMinute >= 0 && istMinute < 50);

const isEscalation = (istHour === 18 && istMinute >= 0 && istMinute < 40);

//const isEscalation = (istHour === 12 && istMinute >= 30 && istMinute < 50);

//const isEscalation = true ;

const isAnySlot   = isReminder1 || isReminder2 || isReminder3 || isEscalation;

const isReminder = isReminder1 || isReminder2 || isReminder3;

// final routing flag
const route =
  isEscalation ? 'ESCALATION' :
  isReminder   ? 'REMINDER'   :
  'NONE';


const triggerSlot = isReminder1 ? '10:30am' : isReminder2 ? '1pm' : isReminder3 ? '5pm' : isEscalation ? '6:30pm' : 'unknown';

console.log(`\n${'═'.repeat(60)}`);
console.log(`🚀 DUAL WEBHOOK ENGINE | IST: ${istHour}:${String(istMinute).padStart(2,'0')} | Slot: ${triggerSlot}`);
console.log('═'.repeat(60));

if (!isAnySlot) {
  console.log(`⏱ Not a scheduled slot — skipping.`);
  return [{ json: { hasDeals: false, message: `Not a scheduled slot (${istHour}:${String(istMinute).padStart(2,'0')} IST)`, runDate: todayStr } }];
}

// ── Date window ───────────────────────────────────────────
function parseDateStr(str) {
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}
function parseBitrixDate(dateStr) {
  if (!dateStr) return null;
  const part = new Date(dateStr).toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  return parseDateStr(part);
}
function formatDate(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return '—';
  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
}

const today       = parseDateStr(todayStr);
const windowStart = new Date(today); windowStart.setDate(windowStart.getDate() - 30);
const windowEnd   = new Date(today); windowEnd.setDate(windowEnd.getDate() + 30);

function classifyDate(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return 'IGNORE';
  if (d < windowStart) return 'IGNORE';
  if (d > windowEnd)   return 'IGNORE';
  if (d < today)       return 'PAST_OVERDUE';
  if (d.getTime() === today.getTime()) return 'TODAY';
  return 'UPCOMING';
}
function daysOverdue(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return 0;
  return Math.floor((today - d) / 86400000);
}
function daysUntil(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return 0;
  return Math.floor((d - today) / 86400000);
}
function dealUrl(id)  { return `${BITRIX_DOMAIN}/crm/deal/details/${id}/`; }
function leadUrl(id)  { return `${BITRIX_DOMAIN}/crm/lead/details/${id}/`; }
function entityUrl(ownerTypeId, ownerId) {
  return ownerTypeId === '1' ? leadUrl(ownerId) : ownerTypeId === '2' ? dealUrl(ownerId) : `${BITRIX_DOMAIN}/crm/`;
}

const ACTIVITY_TYPE  = { '1':'Call','2':'Meeting','3':'Task','4':'Email','6':'Follow-up' };
const OWNER_TYPE_LBL = { '1':'Lead','2':'Deal' };

// ────────────────────────────────────────────────────────────
// STEP 1 — Fetch departments
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 1 — Fetching departments`);
let deptRes;
try {
  deptRes = await this.helpers.request({ method: 'GET', url: `${MAIN_WEBHOOK}/department.get.json`, json: true });
} catch(e) { throw new Error(`[MAIN] Dept fetch failed: ${e.message}`); }

const deptMap = {};
for (const d of (deptRes.result || [])) deptMap[String(d.ID)] = d.NAME || `Dept #${d.ID}`;

const targetDeptIds = Object.entries(deptMap)
  .filter(([, name]) => name.toLowerCase().includes(TARGET_DEPARTMENT.toLowerCase()))
  .map(([id]) => id);

console.log(`   ✅ ${Object.keys(deptMap).length} total depts found`);
console.log(`   🎯 Target dept IDs: [${targetDeptIds.join(', ')}] for "${TARGET_DEPARTMENT}"`);

if (targetDeptIds.length === 0) {
  throw new Error(`Department "${TARGET_DEPARTMENT}" not found. Available: ${Object.values(deptMap).join(', ')}`);
}

// ────────────────────────────────────────────────────────────
// STEP 2 — Build userMap based on mode
// ────────────────────────────────────────────────────────────
const targetSpecific = SELECTED_EMPLOYEES.length > 0;
const selectedIds    = SELECTED_EMPLOYEES.map(e => String(e.id));
const userMap        = {};

if (targetSpecific) {
  // ── MODE A: Specific employees only ──────────────────────
  console.log(`\n👤 STEP 2 — MODE A: Loading ${SELECTED_EMPLOYEES.length} specific employee(s)`);

  for (const emp of SELECTED_EMPLOYEES) {
    userMap[String(emp.id)] = {
      id:    String(emp.id),
      name:  emp.name,
      email: emp.email
    };
    console.log(`   ✅ Added: ${emp.name} (${emp.id})`);
  }

} else {
  // ── MODE B: ALL active users — fetch everyone, filter client-side ──
  console.log(`\n👥 STEP 2 — MODE B: Fetching ALL active users (will filter by dept client-side)`);

  let allUsers = [], uStart = 0, uMore = true;

  while (uMore) {
    try {
      const res = await this.helpers.request({
        method: 'GET',
        url: `${MAIN_WEBHOOK}/user.get.json?filter[ACTIVE]=true&start=${uStart}`,
        json: true
      });
      const batch = res.result || [];
      allUsers = allUsers.concat(batch);
      console.log(`   📦 Fetched batch: ${batch.length} users (total so far: ${allUsers.length})`);
      uMore = !!(res.next && batch.length > 0);
      if (uMore) uStart = res.next;
    } catch(e) { throw new Error(`[MAIN] User fetch failed: ${e.message}`); }
  }

  console.log(`   ✅ ${allUsers.length} total active users fetched`);

  // Filter client-side: keep only users whose dept list overlaps with targetDeptIds
  for (const u of allUsers) {
    const uid = String(u.ID);

    // UF_DEPARTMENT can be an array (multiple depts) or a single value
    const userDeptIds = Array.isArray(u.UF_DEPARTMENT)
      ? u.UF_DEPARTMENT.map(String)
      : (u.UF_DEPARTMENT ? [String(u.UF_DEPARTMENT)] : []);

    const inTargetDept = userDeptIds.some(d => targetDeptIds.includes(d));
    if (!inTargetDept) continue;

    let email = '';
    if (Array.isArray(u.EMAIL))           email = u.EMAIL[0]?.VALUE || '';
    else if (typeof u.EMAIL === 'string') email = u.EMAIL;

    userMap[uid] = {
      id:    uid,
      name:  `${u.NAME || ''} ${u.LAST_NAME || ''}`.trim() || 'Unknown',
      email: email.trim()
    };
  }

  console.log(`   🎯 ${Object.keys(userMap).length} users belong to "${TARGET_DEPARTMENT}"`);
  for (const u of Object.values(userMap)) {
    console.log(`      • ${u.name} (${u.id}) — ${u.email || 'no email'}`);
  }
}

if (Object.keys(userMap).length === 0) {
  return [{ json: { hasDeals: false, message: `No users found in "${TARGET_DEPARTMENT}"`, triggerSlot, runDate: todayStr } }];
}

// ────────────────────────────────────────────────────────────
// STEP 3 — Fetch ALL open deals
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 3 — Fetching open deals`);
let allDeals = [], dStart = 0, dMore = true;
while (dMore) {
  try {
    const res = await this.helpers.request({
      method: 'GET',
      url: `${ACTIVITY_WEBHOOK}/crm.deal.list.json?filter[CLOSED]=N` +
           `&select[]=ID&select[]=TITLE&select[]=CLOSEDATE&select[]=BEGINDATE` +
           `&select[]=DATE_MODIFY&select[]=ASSIGNED_BY_ID&select[]=STAGE_ID` +
           `&start=${dStart}`,
      json: true
    });
    allDeals = allDeals.concat(res.result || []);
    dMore = !!(res.next && (res.result || []).length > 0);
    if (dMore) dStart = res.next;
  } catch(e) { throw new Error(`[ACTIVITY] Deal fetch failed: ${e.message}`); }
}
console.log(`   ✅ ${allDeals.length} open deals`);

const dealMap = {};
for (const d of allDeals) dealMap[String(d.ID)] = d;

// ────────────────────────────────────────────────────────────
// STEP 4 — Fetch incomplete activities for these users
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 4 — Fetching activities for ${Object.keys(userMap).length} user(s)`);
let allActivities = [];
const userIds        = Object.keys(userMap);
const windowStartStr = windowStart.toISOString().slice(0, 10);
const windowEndStr   = windowEnd.toISOString().slice(0, 10);

for (const uid of userIds) {
  let aStart = 0;
  let aMore = true;

  console.log(`   🔍 Fetching activities for user ${uid}`);

  while (aMore) {
    try {
      const res = await this.helpers.request({
        method: 'GET',
        url: `${ACTIVITY_WEBHOOK}/crm.activity.list.json` +
             `?filter[RESPONSIBLE_ID]=${uid}` +
             `&filter[COMPLETED]=N` +
             `&filter[>=DEADLINE]=${windowStartStr}` +
             `&filter[<=DEADLINE]=${windowEndStr}` +
             `&select[]=ID&select[]=SUBJECT&select[]=DEADLINE&select[]=COMPLETED` +
             `&select[]=RESPONSIBLE_ID&select[]=TYPE_ID` +
             `&select[]=OWNER_ID&select[]=OWNER_TYPE_ID` +
             `&start=${aStart}`,
        json: true
      });

      const batch = res.result || [];
      allActivities = allActivities.concat(batch);

      aMore = !!(res.next && batch.length > 0);
      if (aMore) aStart = res.next;

    } catch(e) {
      throw new Error(`[ACTIVITY] Activity fetch failed for user ${uid}: ${e.message}`);
    }
  }
}
console.log(`   ✅ ${allActivities.length} incomplete activities found`);

// ────────────────────────────────────────────────────────────
// STEP 5 — Group & classify activities per user
// ────────────────────────────────────────────────────────────
const grouped = {};
let skippedDept = 0, skippedDate = 0, skippedCompleted = 0;

for (const act of allActivities) {
  const responsibleId = String(act.RESPONSIBLE_ID);

  if (!userMap[responsibleId]) { skippedDept++; continue; }
  if (act.COMPLETED === 'Y')   { skippedCompleted++; continue; }

  const status = classifyDate(act.DEADLINE);
  if (status === 'IGNORE') { skippedDate++; continue; }

  const ownerTypeId = String(act.OWNER_TYPE_ID || '');
  const ownerId     = String(act.OWNER_ID || '');
  const user        = userMap[responsibleId];

  let entityTitle = act.SUBJECT || 'No Subject';
  const linkedId  = ownerId || null;

  if (ownerTypeId === '2' && dealMap[ownerId]) {
    entityTitle = dealMap[ownerId].TITLE || `Deal #${ownerId}`;
  } else if (ownerTypeId === '1') {
    entityTitle = `Lead #${ownerId}`;
  }

  if (!grouped[responsibleId]) {
    grouped[responsibleId] = {
      employee: { id: responsibleId, name: user.name, email: user.email },
      overdue:  [],
      today:    [],
      upcoming: [],
      all:      []
    };
  }

  const item = {
    id:                String(act.ID),
    subject:           act.SUBJECT || 'No Subject',
    activityType:      ACTIVITY_TYPE[String(act.TYPE_ID)] || 'Activity',
    entityType:        OWNER_TYPE_LBL[ownerTypeId] || 'CRM',
    entityTitle,
    ownerTypeId,
    ownerId:           linkedId,
    deadline:          act.DEADLINE,
    deadlineFormatted: formatDate(act.DEADLINE),
    status,
    daysOverdue:       status === 'PAST_OVERDUE' ? daysOverdue(act.DEADLINE) : 0,
    daysUntil:         status === 'UPCOMING'     ? daysUntil(act.DEADLINE)   : 0,
    url:               entityUrl(ownerTypeId, linkedId)
  };

  grouped[responsibleId].all.push(item);
  if (status === 'PAST_OVERDUE') grouped[responsibleId].overdue.push(item);
  if (status === 'TODAY')        grouped[responsibleId].today.push(item);
  if (status === 'UPCOMING')     grouped[responsibleId].upcoming.push(item);
}

console.log(`\n📊 FINAL SUMMARY`);
console.log(`   ⬜ Skipped (not in scope) : ${skippedDept}`);
console.log(`   ⬜ Skipped (completed)    : ${skippedCompleted}`);
console.log(`   ⬜ Skipped (date window)  : ${skippedDate}`);
console.log(`   ✅ Users with activities  : ${Object.keys(grouped).length}`);
for (const [, data] of Object.entries(grouped)) {
  console.log(`      ${data.employee.name}: 🔴${data.overdue.length} overdue | 🟡${data.today.length} today | 🔵${data.upcoming.length} upcoming`);
}

// ────────────────────────────────────────────────────────────
// STEP 6 — Build output
// ────────────────────────────────────────────────────────────
const statusOrder = { 'PAST_OVERDUE': 0, 'TODAY': 1, 'UPCOMING': 2 };
const output = Object.values(grouped).map(empData => {
  empData.all.sort((a, b) => {
    const so = statusOrder[a.status] - statusOrder[b.status];
    return so !== 0 ? so : parseBitrixDate(a.deadline) - parseBitrixDate(b.deadline);
  });

  return {
    json: {
      employee:        empData.employee,
      deals:           empData.all,
      overdueItems:    empData.overdue,
      todayItems:      empData.today,
      upcomingItems:   empData.upcoming,
      overdueCount:    empData.overdue.length,
      todayCount:      empData.today.length,
      upcomingCount:   empData.upcoming.length,
      totalDeals:      empData.all.length,
      hasDeals:        empData.all.length > 0,
      triggerSlot,

       isReminder,
    isEscalation,
    route,

      mainWebhook:     MAIN_WEBHOOK,
      activityWebhook: ACTIVITY_WEBHOOK,
      brevoApiKey:     BREVO_API_KEY,
      fromEmail:       FROM_EMAIL,
      fromName:        FROM_NAME,
      hodUserId:       HOD_USER_ID,
      hodName:         HOD_NAME,
      hodEmail:        HOD_EMAIL,
      bitrixDomain:    BITRIX_DOMAIN,
      maxDealsPerMsg:  MAX_DEALS_PER_MSG,
      runDate:         todayStr
    }
  };
});

if (output.length === 0) {
  return [{
    json: {
      hasDeals:   false,
      message:    `No activities in window (±30 days) for "${TARGET_DEPARTMENT}"`,

       isReminder,
    isEscalation,
    route,


      triggerSlot,
      runDate:    todayStr
    }
  }];
}

return output;
